SHEETS_DRUCK = {
    "direkt":  "Direkt",
    "mk":      "MK",
    "nms":     "HuPa_NMS",
    "malchow": "HuPa_Malchow",
}


def generate_druck_html(up, logo_up, fcsb_file=None) -> str:
    logo_uri = logo_file_to_data_uri(logo_up) or load_logo_data_uri()
    all_data: dict = {}

    _SHEETS_ALT = {
        "direkt":  "Direkt 1 - 99",
        "mk":      "Hupa MK 882",
        "nms":     "Hupa 2221-4444",
        "malchow": "Hupa 7773-7779",
    }
    for area_key, sheet_name in SHEETS_DRUCK.items():
        with st.spinner(f"Verarbeite: {sheet_name} ..."):
            df = None
            for sn in [sheet_name, _SHEETS_ALT.get(area_key, "")]:
                if not sn:
                    continue
                try:
                    up.seek(0)
                    df = pd.read_excel(up, sheet_name=sn)
                    break
                except Exception:
                    continue
            if df is None:
                continue

        cols    = df.columns.tolist()
        trip    = detect_triplets(cols)
        neue    = detect_neue_triplets(cols)   # neues Format: Montag_Zeit / Montag_Sort / Montag_Tag
        bmap    = detect_bspalten(cols)
        nbmap   = detect_neue_bspalten(cols)   # neues B-Format: "Die 1001 B_Zeit" etc.
        ds_trip = detect_ds_triplets(cols)
        data: dict = {}

        for _, r in df.iterrows():
            knr = norm_val(r.get("Nr", ""))
            if not knr: continue
            bestell: list = []
            for d_de in DAYS_DE:
                day_items: list = []
                if d_de in trip:
                    for gt, f_cols in trip[d_de].items():
                        s   = norm_val(r.get(f_cols.get("Sort")))
                        t   = safe_time(r.get(f_cols.get("Zeit")))
                        tag = norm_val(r.get(f_cols.get("Tag")))
                        if s or t or tag:
                            day_items.append({
                                "liefertag": d_de, "sortiment": s,
                                "bestelltag": tag, "bestellschluss": t,
                                "prio": SORT_PRIO.get(canon_group_id(s), 50),
                            })
                # Neues Format: Montag_Zeit / Montag_Sort / Montag_Tag
                for nt in neue:
                    if nt["liefertag"] != d_de:
                        continue
                    s   = norm_val(r.get(nt["sort_col"]))   if nt.get("sort_col") else ""
                    t   = safe_time(r.get(nt["zeit_col"]))  if nt.get("zeit_col") else ""
                    tag = norm_val(r.get(nt["tag_col"]))    if nt.get("tag_col")  else ""
                    if s or t or tag:
                        day_items.append({
                            "liefertag": d_de, "sortiment": s,
                            "bestelltag": tag, "bestellschluss": t,
                            "prio": SORT_PRIO.get(canon_group_id(s), 50),
                        })
                for bk in [k for k in bmap if k[0] == d_de]:
                    bf    = bmap[bk]
                    s     = norm_val(r.get(bf.get("sort", "")))
                    z     = safe_time(r.get(bf.get("zeit", "")))
                    l_col = bf.get("l")
                    tag   = norm_val(r.get(l_col, "")) if l_col else bk[2]
                    if not tag: tag = bk[2]
                    if s or z:
                        day_items.append({
                            "liefertag": d_de, "sortiment": s,
                            "bestelltag": tag, "bestellschluss": z,
                            "prio": SORT_PRIO.get(canon_group_id(s), 50),
                        })
                # Neues B-Format: "Die 1001 B_Zeit" / "Die 1001 B_Sortiment" / "Die 1001 B_Tag"
                for nbk in [k for k in nbmap if k[0] == d_de]:
                    nbf = nbmap[nbk]
                    s   = norm_val(r.get(nbf.get("sort", "")))
                    z   = safe_time(r.get(nbf.get("zeit", "")))
                    tag = norm_val(r.get(nbf.get("tag", "")))
                    if s or z:
                        day_items.append({
                            "liefertag": d_de, "sortiment": s,
                            "bestelltag": tag, "bestellschluss": z,
                            "prio": SORT_PRIO.get(canon_group_id(s), 50),
                        })
                if d_de in ds_trip:
                    for k_ds, f_cols in ds_trip[d_de].items():
                        s   = norm_val(r.get(f_cols.get("Sort")))
                        t   = safe_time(r.get(f_cols.get("Zeit")))
                        tag = norm_val(r.get(f_cols.get("Tag")))
                        if s or t or tag:
                            day_items.append({
                                "liefertag": d_de, "sortiment": s,
                                "bestelltag": tag, "bestellschluss": t,
                                "prio": 5.5,
                            })
                day_items.sort(key=lambda x: x["prio"])
                bestell.extend(day_items)

            data[knr] = {
                "plan_typ":    "",
                "bereich":     BEREICH,
                "kunden_nr":   knr,
                "sap_nummer":  norm_val(r.get("SAP-Nr.", "")),
                "name":        norm_val(r.get("Name",        "")),
                "strasse":     norm_val(r.get("Strasse",     "")),
                "plz":         norm_val(r.get("Plz",         "")),
                "ort":         norm_val(r.get("Ort",         "")),
                "fachberater": norm_val(r.get("Fachberater", "")),
                "tours":       {d: norm_val(r.get(TOUR_COLS[d], "")) for d in DAYS_DE},
                "bestell":     bestell,
            }

        all_data[area_key] = data
        st.success(f"✓ {sheet_name}: {len(data)} Kunden verarbeitet")

    # Ladefolge aus Marktschlüssel-Excel (Mo-Sa Winter)
    ladefolge_map: dict = {}
    try:
        up.seek(0)
        ladefolge_map = build_winter_map(up)
    except Exception:
        pass

    json_data      = json.dumps(all_data,      ensure_ascii=False, separators=(",", ":"))
    ladefolge_json = json.dumps(ladefolge_map, ensure_ascii=False, separators=(",", ":"))

    # Notizen aus Blatt "q" der Kundenliste
    notizen_map: dict = {}
    if fcsb_file is not None:
        try:
            fcsb_file.seek(0)
        except Exception:
            pass
        notizen_map = build_kunden_notizen(fcsb_file)
    notizen_json = json.dumps(notizen_map, ensure_ascii=False, separators=(",", ":"))

    return (
        DRUCK_HTML_TEMPLATE
        .replace("__DATA_JSON__",      json_data)
        .replace("__LADEFOLGE_JSON__", ladefolge_json)
        .replace("__KUNDEN_NOTIZEN_JSON__", notizen_json)
        .replace("__LOGO_DATAURI__",   logo_uri or "")
    )


